	import redis
	from tornado.options import define, options

	define("port", default=8881, help="run on the given port", type=int)

	client = tornadis.Client()
	client.connect()

	r = redis.StrictRedis()

	class TestData(tornado.web.RequestHandler):
		@tornado.gen.coroutine
		def get(self):
			try:
				data = yield get_data()
				self.write(json_util.dumps(data))
				self.finish()
			except Exception as e:
				sys.stderr.write('Error -> %s' % e.message)

	@tornado.gen.coroutine
	def get_data():
		alerts = yield client.call("ZRANGE", "KEY", -5000, -1)
		raise tornado.gen.Return( alerts )

	class Application(tornado.web.Application):
		def __init__(self):
			handlers = [
				(r'/', TestData),
			]

			tornado_settings = dict(
				debug=True,
				auto_reload=True,
			)
			tornado.web.Application.__init__(self, handlers, **tornado_settings)

	def main():
		tornado.options.parse_command_line()
		http_server = tornado.httpserver.HTTPServer( Application() )
		http_server.listen(options.port)
		tornado.ioloop.IOLoop.instance().start()

	if __name__ == '__main__':
		main()

